import { isUndefined } from 'lodash-es';
import { type KeyboardEventHandler } from 'react';

import Colors from '@dynatrace/strato-design-tokens/colors';

import { Knob } from './Knob.js';
import { usePoliteContainer } from '../../../../../overlays/hooks/usePoliteContainer.js';
import { BottomMagnifier } from '../../crosshair/components/BottomMagnifier.js';
import { TopMagnifier } from '../../crosshair/components/TopMagnifier.js';
import { KNOB_WIDTH } from '../../overlays/constants.js';

interface SelectionEdgeProps {
  x: number;
  y: number;
  focusable: boolean;
  interactable: boolean;
  onKeyDown: KeyboardEventHandler;
  onDragMove: (x: number) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
  topLabel?: string;
  bottomLabel?: string;
  chartBounds: DOMRect;
  isBottomLabelRotated?: boolean;
  isTopLabelRotated?: boolean;
  edgeId: string;
  hoveredEdge: string;
  pointerHandlers: {
    onPointerEnter: () => void;
    onPointerLeave: () => void;
  };
}

export const SelectionEdge = ({
  x,
  y,
  focusable,
  interactable,
  onKeyDown,
  onDragMove,
  onDragStart,
  onDragEnd,
  topLabel,
  bottomLabel,
  chartBounds,
  isBottomLabelRotated = false,
  isTopLabelRotated = false,
  edgeId,
  hoveredEdge,
  pointerHandlers,
}: SelectionEdgeProps) => {
  const Portal = usePoliteContainer();

  return (
    <>
      {!isUndefined(bottomLabel) ? (
        <Portal>
          <BottomMagnifier
            label={bottomLabel}
            mouseX={x}
            offset={0}
            color={Colors.Border.Primary.Accent}
            chartBounds={chartBounds}
            isRotated={isBottomLabelRotated}
          />
        </Portal>
      ) : null}
      {!isUndefined(topLabel) ? (
        <Portal>
          <TopMagnifier
            label={topLabel}
            mouseX={x}
            offset={0}
            color={Colors.Border.Primary.Accent}
            chartBounds={chartBounds}
            isRotated={isTopLabelRotated}
          />
        </Portal>
      ) : null}
      <Knob
        edgeId={edgeId}
        hoveredEdge={hoveredEdge}
        y={y}
        x={x - KNOB_WIDTH / 2}
        interactable={interactable}
        focusable={focusable}
        onKeyDown={onKeyDown}
        onDragMove={onDragMove}
        onDragStart={onDragStart}
        onDragEnd={onDragEnd}
        pointerHandlers={pointerHandlers}
      />
    </>
  );
};
